mapper.update:
UPDATE friendships
   SET status = 'ACCEPTED', responded_at = now()
 WHERE id = #{id}
   AND addressee_id = #{addresseeId}
   AND status = 'PENDING'

mapper.delete:
DELETE FROM friendships
 WHERE id = #{id}
   AND addressee_id = #{addresseeId}
   AND status = 'PENDING'

mapper.select:
SELECT f.id AS friendship_id, u.uuid::text AS user_uuid, u.nickname, u.profile_image_url FROM friendships f JOIN users u ON u.id = CASE WHEN f.requester_id = #{viewerId} THEN f.addressee_id ELSE f.requester_id END WHERE f.status = 'ACCEPTED' AND #{viewerId} IN (f.requester_id, f.addressee_id) AND u.deleted_at IS NULL
AND f.id < #{cursor}
ORDER BY f.id DESC LIMIT #{limit}

SELECT f.id AS request_id, u.uuid::text AS user_uuid, u.nickname, u.profile_image_url, f.created_at FROM friendships f JOIN users u ON u.id = f.requester_id WHERE f.addressee_id = #{viewerId} AND f.status = 'PENDING' AND u.deleted_at IS NULL
AND f.id < #{cursor}
ORDER BY f.id DESC LIMIT #{limit}

SELECT f.id AS request_id, u.uuid::text AS user_uuid, u.nickname, u.profile_image_url, f.created_at FROM friendships f JOIN users u ON u.id = f.addressee_id WHERE f.requester_id = #{viewerId} AND f.status = 'PENDING' AND u.deleted_at IS NULL
AND f.id < #{cursor}
ORDER BY f.id DESC LIMIT #{limit}
